import AddOutlined from '@universe-design/icons-react/AddOutlined';
import SettingFilled from '@universe-design/icons-react/SettingFilled';
import React, { useState } from 'react';
import { Collapse } from '..';
// 需要手动引入组件的样式。
import './index.less';
export default {
  title: 'Components/Collapse', // 注意：这里需要修改成自己对应 Component name。
  component: Collapse,
};

export const CollapseControl = () => {
  const [activeKey, setActiveKey] = useState<React.Key[]>(['1']);
  const handleChange = (newActiveKey: React.Key | React.Key[]) => {
    setActiveKey(newActiveKey as React.Key[]);
  };
  return (
    <Collapse onChange={handleChange} activeKey={activeKey} destroyInactivePanel expandIconPosition="right">
      <Collapse.Panel collapsible="header" key="1" header="Collapse Panel header 1">
        mail
      </Collapse.Panel>
      <Collapse.Panel showArrow={false} key="2" header="Collapse Panel header 2" extra={<div>233</div>}>
        im
      </Collapse.Panel>
    </Collapse>
  );
};
CollapseControl.storyName = 'z. 受控模式';

export const CollapseCustom = () => (
  <Collapse
    className="custom-collapse"
    defaultActiveKey={['1', '2']}
    expandIconPosition="left"
    expandIcon={props => <AddOutlined />}
  >
    <Collapse.Panel
      className="custom-collapse-panel"
      key="1"
      header="Collapse Panel header 1"
      extra={
        <span className="custom-collapse-icon">
          <SettingFilled />
        </span>
      }
    >
      This is panel 1 content
    </Collapse.Panel>
    <Collapse.Panel
      key="2"
      header="Collapse Panel header 2"
      extra={
        <span className="custom-collapse-icon">
          <SettingFilled />
        </span>
      }
      className="custom-collapse-panel"
    >
      This is panel 2 content
    </Collapse.Panel>
  </Collapse>
);
CollapseCustom.storyName = 'z. 自定义各种';
